function solve(m: number, n: number, waitCost: number[][]): number {
    // Directions: right (0, 1), down (1, 0)
    const directions = [[0, 1], [1, 0]];

    // Initialize a 2D array to store the minimum cost to reach each cell at each time step
    // Since the time step can be up to (m + n) steps, we'll use a 3D array: [time][i][j]
    // But since the time is determined by the path, we can optimize by using a 2D array for each cell
    // and track the minimum cost to reach that cell at each possible time step.
    // However, to simplify, we can use a 2D array for each cell and track the minimum cost at each time step.
    // We'll use a priority queue (Dijkstra's algorithm) to find the minimum cost path.

    // Priority queue: [totalCost, time, i, j]
    const pq = new PriorityQueue<[number, number, number, number]>();
    pq.enqueue([0, 0, 0, 0]); // Start at (0, 0) at time 0 with total cost 0

    // Distance matrix to store the minimum cost to reach each cell at each time step
    // We'll use a 2D array where each cell contains an array of costs for each time step
    // However, to optimize, we'll use a 2D array where each cell contains the minimum cost to reach it at any time
    const dist = Array(m).fill(0).map(() => Array(n).fill(Infinity));
    dist[0][0] = 0; // Starting at (0, 0) with cost 0

    // Directions for movement: right and down
    const dirs = [[0, 1], [1, 0]];

    while (!pq.isEmpty()) {
        const [totalCost, time, i, j] = pq.dequeue();

        // If we've reached the destination, return the total cost
        if (i === m - 1 && j === n - 1) {
            return totalCost;
        }

        // If the current total cost is higher than the known minimum cost, skip
        if (totalCost > dist[i][j]) {
            continue;
        }

        // Determine if it's an odd or even time step
        const isOddTime = time % 2 === 1;

        // If it's an odd time step, we can move right or down
        if (isOddTime) {
            for (const [dx, dy] of dirs) {
                const ni = i + dx;
                const nj = j + dy;

                // Check if the new cell is within bounds
                if (ni >= 0 && ni < m && nj >= 0 && nj < n) {
                    // Calculate the cost to enter the new cell
                    const enterCost = (ni + 1) * (nj + 1);
                    const newTotalCost = totalCost + enterCost;

                    // Update the distance matrix and priority queue
                    if (newTotalCost < dist[ni][nj]) {
                        dist[ni][nj] = newTotalCost;
                        pq.enqueue([newTotalCost, time + 1, ni, nj]);
                    }
                }
            }
        } 
        // If it's an even time step, we must wait in place
        else {
            // Calculate the cost to wait in the current cell
            const waitCostValue = waitCost[i][j];
            const newTotalCost = totalCost + waitCostValue;

            // Update the distance matrix and priority queue
            if (newTotalCost < dist[i][j]) {
                dist[i][j] = newTotalCost;
                pq.enqueue([newTotalCost, time + 1, i, j]);
            }
        }
    }

    // If we've exhausted all possibilities and haven't reached the destination, return -1 (should not happen)
    return -1;
}

// Priority queue implementation
class PriorityQueue<T> {
    private heap: T[];
    private comparator: (a: T, b: T) => number;

    constructor(comparator: (a: T, b: T) => number) {
        this.heap = [];
        this.comparator = comparator;
    }

    enqueue(item: T): void {
        this.heap.push(item);
        this.heapifyUp(this.heap.length - 1);
    }

    dequeue(): T {
        if (this.heap.length === 0) return undefined as any;
        const item = this.heap[0];
        this.heap[0] = this.heap.pop() as any;
        this.heapifyDown(0);
        return item;
    }

    isEmpty(): boolean {
        return this.heap.length === 0;
    }

    private heapifyUp(index: number): void {
        while (index > 0) {
            const parentIndex = Math.floor((index - 1) / 2);
            if (this.comparator(this.heap[index], this.heap[parentIndex]) >= 0) {
                [this.heap[index], this.heap[parentIndex]] = [this.heap[parentIndex], this.heap[index]];
                index = parentIndex;
            } else {
                break;
            }
        }
    }

    private heapifyDown(index: number): void {
        const leftChild = 2 * index + 1;
        const rightChild = 2 * index + 2;
        let smallest = index;

        if (leftChild < this.heap.length && this.comparator(this.heap[leftChild], this.heap[smallest]) < 0) {
            smallest = leftChild;
        }

        if (rightChild < this.heap.length && this.comparator(this.heap[rightChild], this.heap[smallest]) < 0) {
            smallest = rightChild;
        }

        if (smallest !== index) {
            [this.heap[index], this.heap[smallest]] = [this.heap[smallest], this.heap[index]];
            this.heapifyDown(smallest);
        }
    }
}

