class PriorityQueue<T>(private val comparator: (a: T, b: T) -> Int) {
    private val heap: MutableList<T> = mutableListOf()

    fun enqueue(item: T) {
        heap.add(item)
        heapifyUp(heap.size - 1)
    }

    fun dequeue(): T {
        if (heap.isEmpty()) return java.lang.Object()
        val item = heap[0]
        heap[0] = heap.last()
        heap.removeLast()
        heapifyDown(0)
        return item
    }

    fun isEmpty(): Boolean {
        return heap.isEmpty()
    }

    private fun heapifyUp(index: Int) {
        var node = index
        while (node > 0) {
            val parent = (node - 1) / 2
            if (comparator(heap[node], heap[parent]) >= 0) {
                heap[node] = heap[parent]
                heap[parent] = heap[node]
                node = parent
            } else {
                break
            }
        }
    }

    private fun heapifyDown(index: Int) {
        var node = index
        val left = 2 * node + 1
        val right = 2 * node + 2
        var smallest = node

        if (left < heap.size && comparator(heap[left], heap[smallest]) < 0) {
            smallest = left
        }

        if (right < heap.size && comparator(heap[right], heap[smallest]) < 0) {
            smallest = right
        }

        if (smallest != node) {
            heap[node] = heap[smallest]
            heap[smallest] = heap[node]
            heapifyDown(smallest)
        }
    }
